function report = runCpuOptimizationBaseline(options)
%RUNCPUOPTIMIZATIONBASELINE Freeze the CPU optimization promotion gate.
%
% Runs both CPU-double ZNCC paths and selects either the optimized/vectorized
% or sparse/path-wise pipeline for the reported SGM result. The independent
% reference remains available for numerical comparison.
%
% Traceability: algo/main.tex Secs. 10.4, 11.2--11.4, and 14.6;
% implementation plan Stages C0 and C7.

arguments
    options.ImageSize (1, 2) double ...
        {mustBeFinite, mustBeInteger, mustBePositive} = [96, 112]
    options.TileSize (1, 2) double ...
        {mustBeFinite, mustBeInteger, mustBePositive} = [48, 56]
    options.LabelBlockSize (1, 1) double ...
        {mustBeFinite, mustBeInteger, mustBePositive} = 4
    options.HeightRangeMetres (1, 2) double ...
        {mustBeFinite, mustBeIncreasing} = [-50, 50]
    options.TargetMotionPerLabelPixels (1, 1) double ...
        {mustBeFinite, mustBePositive} = 0.25
    options.UseParallel (1, 1) logical = false
    options.NumWorkers (1, 1) double ...
        {mustBeFinite, mustBeInteger, mustBeNonnegative} = 0
    options.DirectionCount (1, 1) double ...
        {mustBeMember(options.DirectionCount, [4, 8])} = 8
    options.TargetImageSize (1, 2) double ...
        {mustBeFinite, mustBeInteger, mustBePositive} = [5000, 15000]
    options.TargetLabelCounts (1, :) double ...
        {mustBeFinite, mustBeInteger, mustBePositive} = [21, 41, 81]
    options.TargetPrecision (1, 1) string ...
        {mustBeMember(options.TargetPrecision, ["single", "double"])} ...
        = "single"
    options.RowSlabRows (1, 1) double ...
        {mustBeFinite, mustBeInteger, mustBePositive} = 128
    options.CpuImplementation (1, 1) string ...
        {mustBeMember(options.CpuImplementation, ...
        ["optimized", "reference"])} = "optimized"
    options.OutputFile (1, 1) string = ""
end

policy = struct( ...
    "DoubleZnccCostTolerance", 1e-10, ...
    "DoubleSgmCostTolerance", 1e-12, ...
    "TieTolerance", 1e-9, ...
    "SingleStableMargin", 1e-4, ...
    "SingleStableLabelsExact", true, ...
    "SingleMedianEndpointDeltaPixels", 0.01, ...
    "SingleP99EndpointDeltaPixels", 0.05, ...
    "SingleFalseValidIncrease", 0, ...
    "SgmSpeedupTarget", 5, ...
    "TiePolicy", ...
    "label changes are allowed only where reference margin <= TieTolerance");

profile = runDenseProfile( ...
    ImageSize=options.ImageSize, TileSize=options.TileSize, ...
    LabelBlockSize=options.LabelBlockSize, Channel="Zncc", ...
    Channels="Zncc", HeightRangeMetres=options.HeightRangeMetres, ...
    TargetMotionPerLabelPixels=options.TargetMotionPerLabelPixels, ...
    UseParallel=options.UseParallel, NumWorkers=options.NumWorkers, ...
    StoreCostVolumes=true, RunOptimizedZncc=true);
z = profile.HeightLabelsMetres;
equivalence = profile.OptimizedZnccEquivalence;
if options.CpuImplementation == "optimized"
    selectedZncc = profile.OptimizedZnccResult;
    sgm = HeightSgm.aggregateVectorized(selectedZncc.CostVolume, z, ...
        DirectionCount=options.DirectionCount);
    sgmImplementation = "vectorized";
else
    selectedZncc = profile.DenseResult;
    sgm = HeightSgm.aggregate(selectedZncc.CostVolume, z, ...
        DirectionCount=options.DirectionCount);
    sgmImplementation = "reference";
end

memoryCell = cell(1, numel(options.TargetLabelCounts));
for k = 1:numel(options.TargetLabelCounts)
    memoryCell{k} = HeightSweepMemoryEstimator.estimate( ...
        options.TargetImageSize, options.TargetLabelCounts(k), ...
        Precision=options.TargetPrecision, Mode="streamed", ...
        DirectionCount=options.DirectionCount, ...
        RowSlabRows=options.RowSlabRows, ...
        RecomputeBackwardCosts=true);
end
memory = [memoryCell{:}];
labelCount = reshape(options.TargetLabelCounts, [], 1);
oneVolumeGiB = reshape([memory.OneCostVolumeBytes], [], 1) ./ 2 ^ 30;
workingGiB = reshape([memory.SgmWorkingBytes], [], 1) ./ 2 ^ 30;
outputGiB = reshape([memory.OutputBytes], [], 1) ./ 2 ^ 30;
persistentGiB = reshape([memory.PersistentStoreBytes], [], 1) ./ 2 ^ 30;
memoryScenarios = table(labelCount, oneVolumeGiB, workingGiB, ...
    outputGiB, persistentGiB, VariableNames=["Labels", ...
    "OneCostVolumeGiB", "StreamedWorkingGiB", ...
    "RequestedOutputGiB", "PersistentStoreGiB"]);

denseValid = selectedZncc.Valid;
sgmValid = sgm.Valid;
metrics = table( ...
    ["RawWta"; "Sgm"], ...
    [nnz(denseValid); nnz(sgmValid)] ./ prod(options.ImageSize), ...
    [median(abs(selectedZncc.HeightMetres(denseValid))); ...
    median(abs(sgm.HeightMetres(sgmValid)))], ...
    VariableNames=["Method", "Coverage", ...
    "MedianAbsoluteHeightMetres"]);

pool = gcp("nocreate");
if isempty(pool)
    poolType = "none";
    poolWorkers = 0;
else
    poolType = string(class(pool));
    poolWorkers = pool.NumWorkers;
end
machine = struct( ...
    "MatlabRelease", string(version("-release")), ...
    "Computer", string(computer), ...
    "PoolType", poolType, ...
    "PoolWorkers", poolWorkers);

report = struct( ...
    "Policy", policy, ...
    "Machine", machine, ...
    "DenseProfile", profile, ...
    "SgmResult", sgm, ...
    "SelectedZnccResult", selectedZncc, ...
    "CpuImplementation", options.CpuImplementation, ...
    "SgmImplementation", sgmImplementation, ...
    "OptimizedZnccResult", profile.OptimizedZnccResult, ...
    "OptimizedZnccEquivalence", equivalence, ...
    "Metrics", metrics, ...
    "MemoryScenarios", memoryScenarios, ...
    "MemoryEstimates", memory, ...
    "FileIoSeconds", 0, ...
    "RetainedSlabCount", 0, ...
    "LocalFilterOutputSamples", ...
    profile.OptimizedZnccResult.Runtime.LocalFilterOutputSamples, ...
    "LocalFilterSamplesPerSecond", ...
    profile.OptimizedZnccResult.Runtime.LocalFilterSamplesPerSecond, ...
    "NotApplicableDefinition", ...
    "current comparison uses in-memory volumes and no slab I/O", ...
    "CoordinateConvention", ...
    "one-based [x,y]=[column,row] pixel centers", ...
    "WorldFrame", "local ENU metres", ...
    "ElevationDatum", "local synthetic ENU Z=0", ...
    "CostPrecision", "CPU-double; geometry double");

fprintf("CPU optimization baseline (%s/%s): reference ZNCC %.3f s, " ...
    + "optimized ZNCC %.3f s, SGM %.3f s\n", ...
    options.CpuImplementation, sgmImplementation, ...
    profile.DenseResult.Runtime.EvaluationSeconds, ...
    profile.OptimizedZnccResult.Runtime.EvaluationSeconds, ...
    sgm.RuntimeSeconds);
fprintf("  SGM directions (s): %s\n", ...
    strjoin(compose("%.3f", sgm.DirectionRuntimeSeconds), ", "));
fprintf("  SGM tracked arrays: %.3f MiB\n", ...
    sgm.TrackedArrayBytes ./ 2 ^ 20);
disp(metrics);
disp(memoryScenarios);

if options.OutputFile ~= ""
    save(options.OutputFile, "report", "-v7.3");
end
end

function mustBeIncreasing(x)
if x(2) <= x(1)
    error("runCpuOptimizationBaseline:HeightRangeNotIncreasing", ...
        "HeightRangeMetres must be strictly increasing.");
end
end
